from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    if not search_results:
        return {}

    # Initialize aggregations dictionary
    aggregations = defaultdict(lambda: {
        "count": 0,
        "sum_scores": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf'),
        "custom_aggregations": {}
    })

    # Helper function to safely get metadata field value
    def get_metadata_value(result: SearchResult, field: str) -> Any:
        """Extract field value from result metadata, handle missing values."""
        metadata = result.metadata or {}
        return metadata.get(field)

    # First pass: collect raw data for each group
    for result in search_results:
        # Extract group value from metadata
        group_value = get_metadata_value(result, group_by_field)

        # Handle missing group field values
        if group_value is None or group_value == "":
            group_value = "unknown"

        # Update default statistics
        group_data = aggregations[group_value]
        group_data["count"] += 1
        group_data["sum_scores"] += result.score

        # Track max and min scores
        if result.score > group_data["max_score"]:
            group_data["max_score"] = result.score
        if result.score < group_data["min_score"]:
            group_data["min_score"] = result.score

    # Second pass: calculate final statistics and apply custom aggregations
    final_results = {}
    for group_value, data in aggregations.items():
        # Calculate default statistics
        avg_score = data["sum_scores"] / data["count"] if data["count"] > 0 else 0

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                # Get all values for this field across the group
                field_values = []
                for result in search_results:
                    metadata = result.metadata or {}
                    field_value = metadata.get(field_name)
                    if field_value is not None and field_value != "":
                        field_values.append(field_value)

                # Apply the aggregation function
                try:
                    aggregated_value = func(field_values)
                    data["custom_aggregations"][field_name] = aggregated_value
                except Exception as e:
                    # Handle potential errors in custom aggregation functions
                    data["custom_aggregations"][field_name] = f"Error: {str(e)}"

        # Prepare final result dictionary
        group_stats = {
            "count": data["count"],
            "avg_score": round(avg_score, 4),
            "max_score": data["max_score"],
            "min_score": data["min_score"]
        }

        # Add custom aggregations if they exist
        if data["custom_aggregations"]:
            group_stats.update(data["custom_aggregations"])

        final_results[group_value] = group_stats

    return final_results

